from itertools import combinations

class Solution:
    def miceAndCheese(self, reward1, reward2, k):
        n = len(reward1)
        best = None
        for combo in combinations(range(n), k):
            chosen = set(combo)
            total = sum(reward1[i] if i in chosen else reward2[i] for i in range(n))
            if best is None or total > best:
                best = total
        return best

