class Solution:
    def miceAndCheese(self, reward1, reward2, k):
        n = len(reward1)
        base = sum(reward2)
        deltas = sorted((reward1[i] - reward2[i] for i in range(n)), reverse=True)
        return base + sum(deltas[:k])

