var miceAndCheese = function(reward1, reward2, k) {
    const n = reward1.length;
    let base = 0;
    const deltas = [];
    for (let i = 0; i < n; i++) {
        base += reward2[i];
        deltas.push(reward1[i] - reward2[i]);
    }
    deltas.sort((a, b) => b - a);
    let total = base;
    for (let i = 0; i < k; i++) total += deltas[i];
    return total;
};
